+            ])
+            .workload([
+                "BEGIN;",
+                "INSERT INTO t(id, note) VALUES (2, 'transient');",
+                "ROLLBACK;",
+                "SELECT id, note FROM t ORDER BY id;",
+            ])
+            .build();
+
